const emails = $input.all();

if (!emails || emails.length === 0) {
  return [{ json: {
    tem_emails: false,
    total: 0,
    resumo_bruto: 'Nenhum email nao lido na caixa de entrada.',
    data: new Date().toLocaleDateString('pt-BR', { timeZone: 'America/Araguaina' })
  }}];
}

const lista = emails.map((e, i) => {
  const headers = e.json.payload?.headers || [];
  const getHeader = (name) => {
    const h = headers.find(h => h.name.toLowerCase() === name.toLowerCase());
    return h ? h.value : '(sem info)';
  };

  const from = getHeader('From');
  const subject = getHeader('Subject');
  const date = getHeader('Date');

  // Extrair nome do remetente
  const nomeMatch = from.match(/^([^<]+)/);
  const nome = nomeMatch ? nomeMatch[1].trim().replace(/"/g, '') : from;

  return `${i+1}. De: ${nome}\n   Assunto: ${subject}\n   Data: ${date}`;
}).join('\n\n');

const data = new Date().toLocaleDateString('pt-BR', { timeZone: 'America/Araguaina' });

return [{ json: {
  tem_emails: true,
  total: emails.length,
  resumo_bruto: lista,
  data: data
}}];
